package com.izonehub.stores.user;
import com.izonehub.stores.common.BaseEntity;import com.izonehub.stores.store.Store;import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="app_users") public class AppUser extends BaseEntity{ @Column(nullable=false) private String fullName; @Column(nullable=false,unique=true) private String email; @Column(nullable=false) private String passwordHash; @Enumerated(EnumType.STRING) @Column(nullable=false) private Role role; @ManyToOne(fetch=FetchType.LAZY) private Store assignedStore; @Column(nullable=false) private boolean active=true; @Column(nullable=false) private boolean forcePasswordChange=true; @Column(nullable=false) private int failedLoginAttempts=0; @Column(nullable=false) private boolean locked=false; @ManyToOne(fetch=FetchType.LAZY) private AppUser createdBy; private Instant lastLogin;
protected AppUser(){} public AppUser(String fullName,String email,String passwordHash,Role role,Store assignedStore,AppUser createdBy){this.fullName=fullName;this.email=email.toLowerCase();this.passwordHash=passwordHash;this.role=role;this.assignedStore=assignedStore;this.createdBy=createdBy;} public String getFullName(){return fullName;} public String getEmail(){return email;} public String getPasswordHash(){return passwordHash;} public Role getRole(){return role;} public Store getAssignedStore(){return assignedStore;} public boolean isActive(){return active;} public boolean isForcePasswordChange(){return forcePasswordChange;} public int getFailedLoginAttempts(){return failedLoginAttempts;} public boolean isLocked(){return locked;} public Instant getLastLogin(){return lastLogin;} public void deactivate(){active=false;} public void unlock(){locked=false;failedLoginAttempts=0;} public void recordFailedLogin(int max){failedLoginAttempts++; if(failedLoginAttempts>=max) locked=true;} public void recordSuccessfulLogin(){failedLoginAttempts=0;locked=false;lastLogin=Instant.now();} public void changePassword(String hash){passwordHash=hash;forcePasswordChange=false;}}
